// isPrivateIP checks if an IP address is private or loopback
func isPrivateIP(ip string) bool {
	parsedIP := net.ParseIP(ip)
	if parsedIP == nil {
		return false
	}

	if parsedIP.IsLoopback() || parsedIP.IsPrivate() {
		return true
	}

	// Check for link-local addresses
	if parsedIP.IsLinkLocalUnicast() || parsedIP.IsLinkLocalMulticast() {
		return true
	}

	return false
}

// validateURL performs SSRF protection checks
func validateURL(targetURL string) error {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	// Resolve hostname to IP and check if it's private
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname")
	}

	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	if len(ips) == 0 {
		return fmt.Errorf("hostname did not resolve to any IP")
	}

	for _, ip := range ips {
		if isPrivateIP(ip.String()) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		ctx.SetContentType("application/json; charset=utf-8")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Method not allowed"})
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json; charset=utf-8")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Invalid JSON"})
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json; charset=utf-8")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "URL is required"})
		return
	}

	// Validate URL with SSRF protection
	if err := validateURL(targetURL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.SetContentType("application/json; charset=utf-8")
		json.NewEncoder(ctx).Encode(map[string]string{"error": err.Error()})
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Create a context with timeout
	requestCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		select {
		case <-requestCtx.Done():
			ctx.SetStatusCode(fasthttp.StatusRequestTimeout)
			ctx.SetContentType("application/json; charset=utf-8")
			json.NewEncoder(ctx).Encode(map[string]string{"error": "Request timeout"})
			return
		default:
			ctx.SetStatusCode(fasthttp.StatusBadGateway)
			ctx.SetContentType("application/json; charset=utf-8")
			json.NewEncoder(ctx).Encode(map[string]string{"error": fmt.Sprintf("Failed to fetch URL: %v", err)})
			return
		}
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json; charset=utf-8")
		json.NewEncoder(ctx).Encode(map[string]string{"error": fmt.Sprintf("Unexpected status code: %d", res.StatusCode())})
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		ctx.SetContentType("application/json; charset=utf-8")
		json.NewEncoder(ctx).Encode(map[string]string{"error": "Empty response body"})
