		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
		return
	}

	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "URL returned status code: " + string(rune(httpResp.StatusCode())),
		})
		return
	}

	title, description := parseHTMLPreview(httpResp.Body())

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func parseHTMLPreview(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
