// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip string) bool {
	parsedIP := net.ParseIP(ip)
	if parsedIP == nil {
		return false
	}

	// Check for private ranges
	if parsedIP.IsPrivate() || parsedIP.IsLoopback() || parsedIP.IsLinkLocalUnicast() {
		return true
	}

	return false
}

// validateURL performs SSRF protection checks
func validateURL(urlStr string) error {
	// Parse the URL
	parsedURL, err := url.Parse(urlStr)
	if err != nil {
		return err
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return err
	}

	// Get the hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return err
	}

	// Resolve hostname to IP with timeout
	resolver := &net.Resolver{
		PreferGo: true,
		Dial: func(ctx interface{}, network, address string) (net.Conn, error) {
