// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip string) bool {
	parsedIP := net.ParseIP(ip)
	if parsedIP == nil {
		return false
	}

	// Check for private IPv4 ranges
	if parsedIP.IsPrivate() || parsedIP.IsLoopback() || parsedIP.IsLinkLocalUnicast() {
		return true
	}

	// Check for reserved ranges
	if parsedIP.String() == "0.0.0.0" {
		return true
	}

	return false
}

// validateURL validates the URL to prevent SSRF attacks
func validateURL(urlString string) error {
	// Parse the URL
	parsedURL, err := url.Parse(urlString)
	if err != nil {
		return err
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return err
	}

	// Get the hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return err
	}

	// Resolve the hostname to IP
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return err
	}

	// Check if any resolved IP is private
	for _, ip := range ips {
		if isPrivateIP(ip.String()) {
			return err
		}
	}

	return nil
}

// FetchURLPreview handles the POST request to fetch URL preview
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Parse the incoming JSON request
	var req RequestBody
	err := json.Unmarshal(ctx.PostBody(), &req)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "Invalid JSON body",
		})
		return
	}

	// Validate URL
	if req.URL == "" {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "URL field is required",
		})
		return
	}

	// Validate URL to prevent SSRF
	if err := validateURL(req.URL); err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "Invalid or forbidden URL",
		})
		return
	}

	// Create a fasthttp client with timeout
	client := &fasthttp.Client{
		Dial:            fasthttp.DialDualStack,
		ReadTimeout:     5 * time.Second,
		WriteTimeout:    5 * time.Second,
		MaxConnsPerHost: 1,
	}

	// Create a request
	request := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(request)
	request.SetRequestURI(req.URL)
	request.Header.SetMethod(fasthttp.MethodGet)
	request.Header.Set("User-Agent", "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")

	// Create a response
	response := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(response)

