	err = client.DoRedirects(request, response, 5)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(ResponseBody{
			Error: "Failed to fetch URL: " + err.Error(),
		})
		return
	}

	// Parse HTML content
	htmlContent := string(response.Body())
	title := extractTitle(htmlContent)
	description := extractMetaDescription(htmlContent)

	// Return the response
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(ResponseBody{
		Title:       title,
		Description: description,
	})
}

// extractTitle extracts the title from HTML content
func extractTitle(html string) string {
	// Case-insensitive regex to match <title> tag
	re := regexp.MustCompile(`(?i)<title[^>]*>([^<]+)</title>`)
	matches := re.FindStringSubmatch(html)
	if len(matches) > 1 {
		return strings.TrimSpace(matches[1])
	}
	return ""
}

// extractMetaDescription extracts the meta description from HTML content
func extractMetaDescription(html string) string {
	// Case-insensitive regex to match meta description tag
	re := regexp.MustCompile(`(?i)<meta\s+name=["']?description["']?\s+content=["']([^"']+)["']`)
