		for _, resolvedIP := range ips {
			if resolvedIP.IsLoopback() || resolvedIP.IsPrivate() || resolvedIP.IsLinkLocalUnicast() || resolvedIP.IsLinkLocalMulticast() {
				return fmt.Errorf("resolved IP is in private range")
			}
		}
	}

	return nil
}

// executeRequestWithRedirectValidation performs HTTP request with redirect validation
func executeRequestWithRedirectValidation(
	ctx context.Context,
	client *fasthttp.Client,
	req *fasthttp.Request,
	res *fasthttp.Response,
	originalURL *url.URL,
) error {
	redirectCount := 0

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		default:
		}

		if err := client.Do(req, res); err != nil {
			return err
		}

		// Check if redirect is needed
		statusCode := res.StatusCode()
		if statusCode != fasthttp.StatusMovedPermanently &&
			statusCode != fasthttp.StatusFound &&
			statusCode != fasthttp.StatusSeeOther &&
			statusCode != fasthttp.StatusTemporaryRedirect &&
			statusCode != fasthttp.StatusPermanentRedirect {
			return nil
		}

		// Check redirect limit
		redirectCount++
		if redirectCount > maxRedirects {
			return fmt.Errorf("too many redirects")
		}

		// Get redirect location
		location := res.Header.Peek("Location")
		if len(location) == 0 {
			return fmt.Errorf("redirect without location header")
		}

		// Parse redirect URL
		redirectURL, err := url.Parse(string(location))
		if err != nil {
			return fmt.Errorf("invalid redirect URL: %w", err)
		}

		// Handle relative redirects
		if !redirectURL.IsAbs() {
			redirectURL = originalURL.ResolveReference(redirectURL)
		}

		// Validate redirect host matches original host (prevent open redirect)
		if redirectURL.Host != "" && redirectURL.Host != originalURL.Host {
			return fmt.Errorf("redirect to different host not allowed")
		}

		// Validate the redirect target host
		if err := validateHost(redirectURL.Host); err != nil {
			return fmt.Errorf("redirect target validation failed: %w", err)
		}

		// Update request URI for next iteration
		req.SetRequestURI(redirectURL.String())
	}
}

// parseHTMLPreview extracts title and meta description from HTML
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tokenType := tokenizer.Next()

		switch tokenType {
		case html.ErrorToken:
			if tokenizer.Err() == io.EOF {
				return title, description, nil
			}
			return title, description, tokenizer.Err()

		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()

			// Extract title
			if token.Data == "title" && title == "" {
				tokenizer.Next()
				if tokenizer.Token().Type == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}

			// Extract meta description
			if token.Data == "meta" && description == "" {
				var name, content string
				for _, attr := range token.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = strings.TrimSpace(content)
				}
			}

			// Early exit if both found
			if title != "" && description != "" {
				return title, description, nil
			}
		}
	}
}

