func isPrivateIP(ip string) bool {
	parsedIP := net.ParseIP(ip)
	if parsedIP == nil {
		return false
	}

	// Check for private IP ranges
	if parsedIP.IsLoopback() || parsedIP.IsPrivate() || parsedIP.IsLinkLocalUnicast() {
		return true
	}

	// Check for reserved ranges
	if parsedIP.String() == "0.0.0.0" {
		return true
	}

	return false
}

func validateURL(urlString string) error {
	parsedURL, err := url.Parse(urlString)
	if err != nil {
		return err
	}

	// Only allow http and https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return &url.Error{Op: "validate", URL: urlString, Err: errors.New("invalid URL scheme")}
	}

	// Resolve hostname and check for private IPs
	host := parsedURL.Hostname()
	if host == "" {
		return &url.Error{Op: "validate", URL: urlString, Err: errors.New("invalid URL")}
	}

	// Resolve IP address
	ips, err := net.LookupIP(host)
	if err != nil {
		return err
	}

	if len(ips) == 0 {
		return &url.Error{Op: "validate", URL: urlString, Err: errors.New("no IP found")}
	}

	// Check if any resolved IP is private
	for _, ip := range ips {
		if isPrivateIP(ip.String()) {
			return &url.Error{Op: "validate", URL: urlString, Err: errors.New("private IP address")}
		}
	}

	return nil
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var req URLPreviewRequest
	err := json.Unmarshal(ctx.PostBody(), &req)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Invalid JSON body",
		})
		return
	}

	if req.URL == "" {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "URL field is required",
		})
		return
	}

	// Validate URL to prevent SSRF
	err = validateURL(req.URL)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Invalid or private URL",
		})
		return
	}

	// Create fasthttp client with timeout
	client := &fasthttp.Client{
		Dial:         fasthttp.DialDualStack,
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod("GET")
	httpReq.Header.Set("User-Agent", "Mozilla/5.0")

	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Fetch URL with timeout and follow redirects
	err = client.DoRedirects(httpReq, httpResp, 10)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
		return
	}

	// Parse HTML content
	title, description := extractMetadata(httpResp.Body())

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(body []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	title := ""
	description := ""

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if name == "description" && content != "" {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	router := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			if string(ctx.Method()) == "POST" {
				FetchURLPreview(ctx)
			} else {
				ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
			}
		default:
			ctx.SetStatusCode(fasthttp.StatusNotFound)
		}
	}

	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

