	parsedURL, err := url.Parse(req.URL)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Invalid URL format",
		})
		return
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Only http and https schemes are allowed",
		})
		return
	}

	// Check for SSRF - prevent access to private IPs
	host := parsedURL.Host
	if isPrivateIP(host) {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusForbidden)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Access to private IP addresses is not allowed",
		})
		return
	}

	// Create fasthttp client with timeout
	client := &fasthttp.Client{
