		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
			return
		}

		resp := PreviewResponse{
			Title:       title,
			Description: description,
		}

		ctx.SetContentType("application/json; charset=utf-8")
		if err := json.NewEncoder(ctx).Encode(resp); err != nil {
			ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
			return
		}
	} else {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
	}
}

// validateHost checks if the host is not a private/reserved IP address to prevent SSRF attacks
func validateHost(host string) error {
	// Remove port if present
	hostname := host
	if idx := strings.LastIndex(host, ":"); idx != -1 {
		hostname = host[:idx]
	}

	// Parse the IP address
	ip := net.ParseIP(hostname)
	if ip != nil {
		// Block private and reserved IP ranges
		if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || 
			ip.IsLinkLocalMulticast() || ip.IsMulticast() || ip.IsUnspecified() {
			return fmt.Errorf("access to private/reserved IP address is not allowed")
		}
	}

	return nil
}

