type URLPreviewRequest struct {
	URL string `json:"url"`
}

type URLPreviewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var req URLPreviewRequest
	err := json.Unmarshal(ctx.PostBody(), &req)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Invalid JSON request body",
		})
		return
	}

	if req.URL == "" {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "URL field is required",
		})
		return
	}

	client := &fasthttp.Client{
		Dial:            fasthttp.DialDualStack,
		MaxConnsPerHost: 100,
		ReadTimeout:     3 * time.Second,
		WriteTimeout:    3 * time.Second,
	}

	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod(fasthttp.MethodGet)
	httpReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreviewBot/1.0)")

	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	err = client.DoRedirects(httpReq, httpResp, 5)
	if err != nil {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "Failed to fetch URL: " + err.Error(),
		})
		return
	}

	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.SetContentType("application/json")
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(URLPreviewResponse{
			Error: "URL returned status code: " + string(rune(httpResp.StatusCode())),
		})
		return
	}

	title, description := extractMetadata(httpResp.Body())

	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(URLPreviewResponse{
		Title:       title,
		Description: description,
	})
}

func extractMetadata(body []byte) (string, string) {
	title := ""
	description := ""

	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return title, description
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" || attr.Key == "property" {
						name = attr.Val
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}

				if (name == "description" || name == "og:description") && description == "" {
					description = content
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	router := func(ctx *fasthttp.RequestCtx) {
		if string(ctx.Path()) == "/preview" && string(ctx.Method()) == "POST" {
			FetchURLPreview(ctx)
		} else {
			ctx.SetStatusCode(fasthttp.StatusNotFound)
			ctx.SetBodyString("Not Found")
		}
	}

	log.Println("Starting server on :8080")
	if err := fasthttp.ListenAndServe(":8080", router); err != nil {
		log.Fatalf("Error starting server: %v", err)
	}
}

