	ErrInvalidScheme = &ValidationError{"invalid URL scheme"}
	ErrInvalidHost   = &ValidationError{"invalid host"}
	ErrPrivateIP     = &ValidationError{"private IP address not allowed"}
)

type ValidationError struct {
	message string
}

func (e *ValidationError) Error() string {
	return e.message
}

