	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: "Failed to encode response"})
		return
	}
}

// isPrivateIP checks if the given hostname/IP is a private or internal address
func isPrivateIP(hostname string) bool {
	if hostname == "" {
		return true
	}

	// Check for localhost
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	// Parse IP address
	ip := net.ParseIP(hostname)
	if ip == nil {
		// If it's not a valid IP, try to resolve it (but this could be slow)
		// For now, we'll allow non-IP hostnames
		return false
	}

	// Check if it's a private IP
	if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}

			if n.Data == "meta" {
				var nameAttr, contentAttr string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						nameAttr = strings.ToLower(attr.Val)
					}
					if attr.Key == "content" {
						contentAttr = attr.Val
					}
				}
				if nameAttr == "description" && contentAttr != "" {
					description = contentAttr
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}

	f(doc)
	return title, description, nil
}

