// validateURLForSSRF checks if the URL points to private/internal networks
func validateURLForSSRF(parsedURL *url.URL) error {
	host := parsedURL.Hostname()
	if host == "" {
		return fmt.Errorf("unable to extract hostname from URL")
	}

	// Reject localhost and loopback addresses
	if host == "localhost" || host == "127.0.0.1" || host == "::1" {
		return fmt.Errorf("localhost addresses are not allowed")
	}

	// Resolve the hostname to IP address
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("unable to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return fmt.Errorf("no IP addresses found for hostname")
	}

	// Check if any resolved IP is private or reserved
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("URL resolves to a private or reserved IP address: %s", ip.String())
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is private or reserved
func isPrivateIP(ip net.IP) bool {
	// Check for private/reserved IP ranges
	return ip.IsPrivate() ||
		ip.IsLoopback() ||
		ip.IsLinkLocalUnicast() ||
		ip.IsLinkLocalMulticast() ||
		ip.IsMulticast() ||
		ip.IsUnspecified()
}

// isHTMLContentType checks if the content type is HTML
func isHTMLContentType(contentType string) bool {
	// Extract the media type (before semicolon)
	mediaType := strings.Split(contentType, ";")[0]
	mediaType = strings.TrimSpace(mediaType)
	return mediaType == "text/html" || strings.HasSuffix(mediaType, "+html")
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	tokenizer := html.NewTokenizer(r)

	for {
		tt := tokenizer.Next()
		switch tt {
		case html.ErrorToken:
			// End of document
			return title, description, nil
		case html.StartTagToken, html.SelfClosingTagToken:
			token := tokenizer.Token()
			switch token.Data {
			case "title":
