	}
}

// isPrivateIP checks if the given hostname/IP is a private IP address
func isPrivateIP(hostname string) bool {
	if hostname == "" {
		return true
	}

	// Block localhost
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" {
		return true
	}

	ip := net.ParseIP(hostname)
	if ip == nil {
		return false
	}

	// Check for private IP ranges
	if ip.IsPrivate() || ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	title = extractTitle(doc)
	description = extractMetaDescription(doc)

	return title, description, nil
}

// extractTitle extracts the title from the HTML document.
func extractTitle(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "title" {
		if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
			return strings.TrimSpace(n.FirstChild.Data)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if title := extractTitle(c); title != "" {
			return title
		}
	}

	return ""
}

// extractMetaDescription extracts the meta description from the HTML document.
func extractMetaDescription(n *html.Node) string {
	if n.Type == html.ElementNode && n.Data == "meta" {
		var name, content string
		for _, attr := range n.Attr {
			if attr.Key == "name" {
				name = strings.ToLower(attr.Val)
			}
			if attr.Key == "content" {
				content = attr.Val
			}
		}
		if name == "description" && content != "" {
			return strings.TrimSpace(content)
		}
	}

	for c := n.FirstChild; c != nil; c = c.NextSibling {
		if desc := extractMetaDescription(c); desc != "" {
			return desc
		}
	}

	return ""
}

